+fn format_pydatetime_naive(value: NaiveDateTime) -> String {
+    let rendered = value.format("%Y-%m-%d %H:%M:%S").to_string();
+    let micros = value.and_utc().timestamp_subsec_micros();
+    if micros == 0 {
+        rendered
+    } else {
+        format!("{rendered}.{micros:06}")
+    }
